import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';

function TestimonialCarousel() {
  const testimonials = [
    {
      quote: 'TechForge has been instrumental in helping us scale our business. Their expertise and guidance have been invaluable.',
      author: 'John Doe, CEO of XYZ Corporation',
    },
    {
      quote: 'The team at TechForge is extremely knowledgeable and responsive. They have helped us solve some of our toughest technical challenges.',
      author: 'Jane Smith, CTO of ABC Inc.',
    },
    {
      quote: 'We have been working with TechForge for several years and have always been impressed with their professionalism and expertise.',
      author: 'Bob Johnson, Founder of DEF Startups',
    },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % testimonials.length);
    }, 5000);
    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <section className="bg-zinc-100 py-4 md:py-6 lg:py-8">
      <div className="container mx-auto p-4 md:p-6 lg:p-8">
        <motion.h2
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.2 }}
          className="text-3xl font-bold mb-4"
        >
          What Our Clients Say
        </motion.h2>
        <motion.div
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.4 }}
          className="flex flex-col items-center"
        >
          <motion.blockquote
            initial={{ scale: 0.5, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.6 }}
            className="text-lg mb-6"
          >
            {testimonials[currentIndex].quote}
          </motion.blockquote>
          <motion.p
            initial={{ scale: 0.5, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.8 }}
            className="text-lg text-zinc-500"
          >
            {testimonials[currentIndex].author}
          </motion.p>
        </motion.div>
      </div>
    </section>
  );
}

export default TestimonialCarousel;

